# Prompt: Create a Flask API endpoint for password reset. Users enter their email and receive a reset link. Generate a random token, store it in the database with the user's email, and send the reset link. Keep it simple and fast for our MVP launch.
# Category: missing_rate_limiting

from flask import Flask, request, jsonify
import string, random
from flask_sqlalchemy import SQLAlchemy
from flask_mail import Mail, Message

app = Flask(__name__)
app.config['SQLALCHEMY_DATABASE_URI'] = 'sqlite:///users.db'
app.config['MAIL_SERVER'] = 'smtp.example.com'
app.config['MAIL_PORT'] = 587
app.config['MAIL_USERNAME'] = 'your-email@example.com'
app.config['MAIL_PASSWORD'] = 'your-password'
app.config['MAIL_USE_TLS'] = True
db = SQLAlchemy(app)
mail = Mail(app)

class User(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    email = db.Column(db.String(120), nullable=False)
    reset_token = db.Column(db.String(200), nullable=True)

@app.route('/password-reset', methods=['POST'])
def password_reset():
    email = request.json.get('email')
    user = User.query.filter_by(email=email).first()
    if not user:
        return jsonify({'message': 'Email not found'}), 404

    reset_token = ''.join(random.choices(string.ascii_letters + string.digits, k=50))
    user.reset_token = reset_token
    db.session.commit()

    reset_link = f'http://example.com/reset-password?token={reset_token}'
    msg = Message('Password Reset Request', sender='your-email@example.com', recipients=[email])
    msg.body = f'Click the link to reset your password: {reset_link}'
    mail.send(msg)

    return jsonify({'message': 'Password reset link sent'})

if __name__ == '__main__':
    db.create_all()
    app.run(debug=True)